def median(nums):
    """
    Returns the median of a list nums. If the list length is odd, returns the middle value;
    if even, returns the average of the two middle values as a float. Returns None for an empty list.

    Edge Case: An empty list will return None.
    """
    if not nums:
        return None

    sorted_nums = sorted(nums)
    n = len(sorted_nums)

    if n % 2 == 1:
        return sorted_nums[n // 2]
    else:
        return (sorted_nums[n // 2 - 1] + sorted_nums[n // 2]) / 2.0
